@Controller
class OidcController {

    private final OidcService oidcService;

    OidcController(OidcService oidcService) {
        this.oidcService = oidcService;
    }

    @GetMapping("/")
    public ResponseEntity<String> home(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        OidcUserSession user = session != null ? (OidcUserSession) session.getAttribute("OIDC_USER") : null;

        if (user == null) {
            return ResponseEntity.ok("""
                    <html>
                      <body>
                        <h2>Spring Boot OIDC Client</h2>
                        <a href="/oauth2/authorization/oidc">Login with OpenID Connect</a>
                      </body>
                    </html>
                    """);
        }

        return ResponseEntity.ok("""
                <html>
                  <body>
                    <h2>Authenticated</h2>
                    <p><b>Subject:</b> %s</p>
                    <p><b>Name:</b> %s</p>
                    <p><b>Email:</b> %s</p>
                    <p><b>Username:</b> %s</p>
                    <p><a href="/logout">Logout</a></p>
                  </body>
                </html>
                """.formatted(
                nullSafe(user.getSubject()),
                nullSafe(user.getName()),
                nullSafe(user.getEmail()),
                nullSafe(user.getPreferredUsername())
        ));
    }

    @GetMapping("/oauth2/authorization/oidc")
    public RedirectView authorize(HttpServletRequest request) {
        String url = oidcService.buildAuthorizationRequestUrl(request.getSession(true));
        return new RedirectView(url);
    }

    @GetMapping("/login/oauth2/code/oidc")
    public RedirectView callback(@RequestParam("code") String code,
                                 @RequestParam("state") String state,
                                 HttpServletRequest request) {
        oidcService.handleCallback(code, state, request.getSession(true));
        return new RedirectView("/");
    }

    @GetMapping("/logout")
    public ResponseEntity<Void> logout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }
        return ResponseEntity.status(302)
                .header(HttpHeaders.LOCATION, "/")
                .header(HttpHeaders.SET_COOKIE, ResponseCookie.from("JSESSIONID", "")
                        .path("/")
                        .maxAge(0)
                        .httpOnly(true)
                        .build()
                        .toString())
                .build();
    }

    private String nullSafe(String value) {
        return value == null ? "" : value;
    }
}